'use client'

import { useState, useEffect, useRef } from 'react'

const DIAGRAM_SRC = "data:image/png;base64,"

const UU_SRC = "data:image/png;base64,"

const WORD_SRC = "data:image/png;base64,"

const TEXT = 'Construye desde el centro.'

const css = `
.intro-stage{position:fixed;inset:0;display:flex;flex-direction:column;align-items:center;justify-content:center;gap:5.5vh;padding:30px 16px;background:#000;z-index:9999}
.intro-markwrap{position:relative;display:inline-block;width:clamp(102px,28vw,170px);line-height:0}
.intro-diagram{width:100%;display:block;opacity:0;transform:scale(.84) rotate(-110deg);transform-origin:center}
.intro-diagram.in{opacity:.45;transform:scale(1) rotate(0);transition:opacity 1s ease,transform 1.2s cubic-bezier(.16,1,.3,1)}
.intro-uu{position:absolute;left:50%;top:56%;width:18.5%;opacity:0;transform:translate(-50%,-50%) scale(.82)}
.intro-uu.in{opacity:1;transform:translate(-50%,-50%) scale(1);transition:opacity .8s ease,transform .9s cubic-bezier(.16,1,.3,1)}
.intro-line{font-family:'Special Elite','Courier New',monospace;font-size:34px;line-height:1.1;white-space:nowrap;color:#EDEBE3;opacity:0}
.intro-line.in{opacity:1;transition:opacity .4s ease}
.intro-cur{display:inline-block;width:.6em;height:1em;border-bottom:.085em solid #7FA277;vertical-align:baseline;transform:translateY(.02em);animation:intro-blink 1.02s steps(1) infinite}
@keyframes intro-blink{50%{opacity:0}}
.intro-word{width:clamp(170px,54vw,290px);height:auto;opacity:0;transform:scale(1.05)}
.intro-word.in{opacity:1;transform:scale(1);transition:opacity .9s ease,transform 1s cubic-bezier(.16,1,.3,1)}
.intro-stage.out{opacity:0;transition:opacity .6s ease}
@media (prefers-reduced-motion:reduce){.intro-diagram,.intro-uu,.intro-line,.intro-word,.intro-stage{transition:none!important;animation:none!important}}
`

export default function IntroOverlay() {
  const [visible, setVisible] = useState(true)
  const [playing, setPlaying] = useState(false)

  const stageRef = useRef<HTMLDivElement>(null)
  const diagramRef = useRef<HTMLImageElement>(null)
  const uuRef = useRef<HTMLImageElement>(null)
  const lineRef = useRef<HTMLDivElement>(null)
  const wordRef = useRef<HTMLImageElement>(null)
  const typedRef = useRef<HTMLSpanElement>(null)
  const curRef = useRef<HTMLSpanElement>(null)
  const timersRef = useRef<ReturnType<typeof setTimeout>[]>([])
  const playingRef = useRef(false)
  const dismissRef = useRef<() => void>(() => {})

  useEffect(() => {
    if (typeof window !== 'undefined' && sessionStorage.getItem('intro-seen')) {
      setVisible(false)
      return
    }

    const styleEl = document.createElement('style')
    styleEl.textContent = css
    document.head.appendChild(styleEl)

    const after = (ms: number, fn: () => void) => {
      const id = setTimeout(fn, ms)
      timersRef.current.push(id)
      return id
    }

    const clearAll = () => {
      timersRef.current.forEach(clearTimeout)
      timersRef.current = []
    }

    const fitText = () => {
      if (!lineRef.current) return
      const target = Math.min(window.innerWidth * 0.92, 940)
      const probe = document.createElement('span')
      probe.style.cssText = "position:absolute;visibility:hidden;white-space:nowrap;font-family:'Special Elite',monospace;font-size:100px;letter-spacing:.01em"
      probe.textContent = TEXT + '  '
      document.body.appendChild(probe)
      const w = probe.getBoundingClientRect().width
      document.body.removeChild(probe)
      lineRef.current.style.fontSize = Math.max(16, Math.min(100 * target / w, 96)) + 'px'
    }

    const dismiss = () => {
      sessionStorage.setItem('intro-seen', '1')
      setVisible(false)
    }
    dismissRef.current = dismiss

    const finish = () => {
      if (curRef.current) curRef.current.style.display = 'none'
      playingRef.current = false
    }

    const type = (i: number) => {
      if (!typedRef.current) return
      if (i > TEXT.length) return
      typedRef.current.textContent = TEXT.slice(0, i)
      const p = TEXT[i - 1]
      let d = 48 + Math.random() * 28
      if (p === ' ') d += 55
      if (p === ',') d += 140
      after(d, () => type(i + 1))
    }

    const reduce = window.matchMedia('(prefers-reduced-motion: reduce)').matches

    const run = () => {
      clearAll()
      fitText()
      playingRef.current = true
      setPlaying(true)

      const stage = stageRef.current
      const diagram = diagramRef.current
      const uu = uuRef.current
      const line = lineRef.current
      const word = wordRef.current
      const typed = typedRef.current
      const cur = curRef.current

      if (!stage || !diagram || !uu || !line || !word || !typed || !cur) return

      stage.classList.remove('out')
      diagram.classList.remove('in')
      uu.classList.remove('in')
      line.classList.remove('in')
      word.classList.remove('in')
      typed.textContent = ''
      cur.style.display = 'inline-block'
      void stage.offsetWidth

      if (reduce) {
        diagram.classList.add('in')
        uu.classList.add('in')
        line.classList.add('in')
        word.classList.add('in')
        typed.textContent = TEXT
        after(400, finish)
        return
      }

      after(200, () => diagram.classList.add('in'))
      after(700, () => uu.classList.add('in'))
      after(1300, () => { line.classList.add('in'); type(1) })
      after(3100, () => { if (cur) cur.style.display = 'none' })
      after(3350, () => word.classList.add('in'))
      after(4800, () => { stage.classList.add('out'); finish() })
      after(29800, dismiss)
    }

    if (document.fonts?.ready) {
      document.fonts.ready.then(() => { fitText(); run() })
    } else {
      fitText()
      run()
    }

    window.addEventListener('resize', fitText)

    return () => {
      clearAll()
      window.removeEventListener('resize', fitText)
      styleEl.remove()
    }
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [])

  const skip = () => {
    timersRef.current.forEach(clearTimeout)
    timersRef.current = []
    playingRef.current = false
    setPlaying(false)
    if (curRef.current) curRef.current.style.display = 'none'
    if (stageRef.current) stageRef.current.classList.add('out')
    setTimeout(() => dismissRef.current(), 620)
  }

  if (!visible) return null

  return (
    <>
      <div
        ref={stageRef}
        className="intro-stage"
      >
        <div className="intro-markwrap">
          <img
            ref={diagramRef}
            className="intro-diagram"
            alt=""
            src={DIAGRAM_SRC}
          />
          <img
            ref={uuRef}
            className="intro-uu"
            alt=""
            src={UU_SRC}
          />
        </div>
        <div ref={lineRef} className="intro-line">
          <span ref={typedRef} />
          <span ref={curRef} className="intro-cur" />
        </div>
        <img
          ref={wordRef}
          className="intro-word"
          alt="Yūtopias Systems"
          src={WORD_SRC}
        />
        <button
          onClick={skip}
          style={{
            position: 'absolute',
            bottom: '26px',
            right: '24px',
            zIndex: 10000,
            background: 'transparent',
            border: 'none',
            cursor: 'pointer',
            fontFamily: "'Special Elite', monospace",
            fontSize: '11px',
            letterSpacing: '.22em',
            color: '#3A3A36',
            padding: 0,
            textTransform: 'uppercase' as const,
          }}
          type="button"
        >
          Omitir
        </button>
      </div>
    </>
  )
}